// ═══════════════════════════════════════════════════════════════
// EQUESTRIA FOOTBALL — logos.js
// Logos clubs, nations, ligues — base64 encodés (180px max)
// Mapping : LOGO_DATA[clubId | natId | leagueId] = data URI
// ═══════════════════════════════════════════════════════════════

'use strict';

const LOGO_DATA = {
  'APOEL_ZAITE': 'data:image/jpeg;base64,',
  'BOURRUSIA_BOUVILLE': 'data:image/jpeg;base64,',
  'BERU_FC': 'data:image/jpeg;base64,',
  'JUVENTUS_EARTH': 'data:image/jpeg;base64,',
  'WONDER_BALLT': 'data:image/jpeg;base64,',
  'BAYERN_ILUMYSS': 'data:image/jpeg;base64,',
  'SUPA_STRIKA': 'data:image/jpeg;base64,',
  'PORT_YONEUVE': 'data:image/jpeg;base64,',
  'ETOILE_ROUGE_BLASE': 'data:image/jpeg;base64,',
  'GEARS_PONEYS': 'data:image/jpeg;base64,',
  'MAGICS_CROCUS': 'data:image/jpeg;base64,',
  'FAR_WEST': 'data:image/jpeg;base64,',
  'BRASIL_NATION': 'data:image/jpeg;base64,',
  'SPORTING_MARITUGA': 'data:image/jpeg;base64,',
  'nat_bermudes': 'data:image/jpeg;base64,',
  'nat_brislovia': 'data:image/jpeg;base64,',
  'nat_ishgar': 'data:image/jpeg;base64,',
  'league_PRO_LIGA': 'data:image/jpeg;base64,',
  'FENRIR': 'data:image/jpeg;base64,',
};

// Helper : retourne l'image ou null
function getLogo(id) { return LOGO_DATA[id] || null; }

// Helper : retourne un <img> HTML ou un emoji fallback
function logoImg(id, size=32, cls='') {
  const src = LOGO_DATA[id];
  if (!src) return '';
  return `<img src="${src}" width="${size}" height="${size}" 
    style="object-fit:contain;border-radius:4px;vertical-align:middle" 
    class="${cls}" alt="${id}" onerror="this.style.display='none'">`;
}
